	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;महाजनपद&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&amp;nbsp;राजधानी&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;कौशल&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;श्रावस्ती&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;कुरु&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;इंद्रप्रस्थ/हस्तिनापुर&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;वज्जि&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;वैशाली&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;गांधार&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;तक्षशिला&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;strong&gt;&amp;#39;Playing It My Way&amp;#39; is the autobiography of Sanchin Tendulkar&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Playing It My Way is the autobiography of &lt;strong&gt;Former Indian cricketer Sachin Tendulkar&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;It was co-authored by &lt;strong&gt;Boria Majumdar&lt;/strong&gt;, an Indian sports journalist along with Sachin.&lt;/li&gt;
	&lt;li&gt;The autobiography was published on&lt;strong&gt; 5 November 2014&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The book describes the&lt;strong&gt; early days of the cricketer, his 24 years of career, and his different aspects of life&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Here, he talks about his cricket journey from his &lt;strong&gt;first Test match to his 100th international century and his farewell &lt;/strong&gt;in this field.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Sachin Tendulkar was born on &lt;strong&gt;24 April 1973&lt;/strong&gt; and started his cricket journey at &lt;strong&gt;the age of 16.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;He was awarded &lt;strong&gt;Bharat Ratna Award &lt;/strong&gt;on the day of his retirement.&lt;/li&gt;
	&lt;li&gt;A Century Is Not Enough is an autobiography of &lt;strong&gt;Sourav Ganguly.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Yuvraj Singh &lt;/strong&gt;is associated with The Test of My Life.&lt;/li&gt;
	&lt;li&gt;The biography of &lt;strong&gt;Rahul Dravid&lt;/strong&gt;, The Nice Guy Who Finished First was written by Devendra Prabhudesai.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;&lt;strong&gt;&amp;#39;प्लेइंग इट माई वे&amp;#39; सचिन तेंदुलकर की आत्मकथा है।&lt;/strong&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;प्लेइंग इट माई वे &lt;strong&gt;पूर्व भारतीय क्रिकेटर सचिन तेंदुलकर &lt;/strong&gt;की आत्मकथा है।&lt;/li&gt;
	&lt;li&gt;यह सचिन के साथ एक भारतीय खेल पत्रकार &lt;strong&gt;बोरिया मजूमदार&lt;/strong&gt; द्वारा सह-लेखक था।&lt;/li&gt;
	&lt;li&gt;आत्मकथा &lt;strong&gt;5 नवंबर 2014 &lt;/strong&gt;को प्रकाशित हुई थी।&lt;/li&gt;
	&lt;li&gt;पुस्तक में &lt;strong&gt;क्रिकेटर के शुरुआती दिनों, उनके 24 साल के करियर और उनके जीवन के विभिन्न पहलुओं &lt;/strong&gt;का वर्णन किया गया है।&lt;/li&gt;
	&lt;li&gt;यहां, वह अपने &lt;strong&gt;पहले टेस्ट मैच से लेकर अपने 100वें अंतरराष्ट्रीय शतक और &lt;/strong&gt;इस क्षेत्र में&lt;strong&gt; अपनी विदाई तक &lt;/strong&gt;के अपने क्रिकेट सफर के बारे में बात कर रहे हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;सचिन तेंदुलकर का जन्म &lt;strong&gt;24 अप्रैल 1973 &lt;/strong&gt;को हुआ था और उन्होंने &lt;strong&gt;16 साल की उम्र&lt;/strong&gt; में अपने क्रिकेट सफर की शुरुआत की थी।&lt;/li&gt;
	&lt;li&gt;उनकी सेवानिवृत्ति के दिन उन्हें &lt;strong&gt;भारत रत्न पुरस्कार &lt;/strong&gt;से सम्मानित किया गया था।&lt;/li&gt;
	&lt;li&gt;ए सेंचुरी इज नॉट इनफ &lt;strong&gt;सौरव गांगुली&lt;/strong&gt; की आत्मकथा है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;युवराज सिंह&lt;/strong&gt; द टेस्ट ऑफ माई लाइफ से जुड़े हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;राहुल द्रविड़&lt;/strong&gt; की जीवनी, द नाइस गाइ हू फिनिश्ड फर्स्ट देवेंद्र प्रभुदेसाई द्वारा लिखी गई थी।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Province&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The term &lt;strong&gt;&amp;#39;Bhukti&amp;#39;&lt;/strong&gt; in post-Gupta period referred to an administrative division or a &lt;strong&gt;province&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Bhuktis were governed by officers known as &lt;strong&gt;&amp;#39;Uparikas&amp;#39;&lt;/strong&gt;, who were appointed by the king.&lt;/li&gt;
	&lt;li&gt;Each Bhukti consisted of multiple &lt;strong&gt;&amp;#39;Vishayas&amp;#39;&lt;/strong&gt; or districts, which were smaller administrative units.&lt;/li&gt;
	&lt;li&gt;The Vishayas were managed by officers called &lt;strong&gt;&amp;#39;Vishayapatis&amp;#39;&lt;/strong&gt;, who reported to the Uparikas of the Bhukti.&lt;/li&gt;
	&lt;li&gt;Bhuktis were a key feature of the decentralized administrative structure during the post-Gupta era.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Uparika:&lt;/strong&gt; The head of a Bhukti, appointed by the king, who held administrative and judicial authority over the province.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Vishaya:&lt;/strong&gt; A sub-division of a Bhukti, equivalent to a district, managed by Vishayapatis.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Post-Gupta Polity:&lt;/strong&gt; This period saw a shift towards a more decentralized administrative system, with provinces playing a critical role in governance.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Decentralization:&lt;/strong&gt; The post-Gupta administration was characterized by a division of power between central and provincial authorities.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Gupta Administration:&lt;/strong&gt; The Gupta era laid the foundation for administrative units like Bhuktis and Vishayas, which continued in post-Gupta polity.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;प्रांत&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;गुप्तोत्तर काल में &lt;strong&gt;&amp;#39;भूक्ति&amp;#39;&lt;/strong&gt; शब्द एक प्रशासनिक विभाग या &lt;strong&gt;प्रांत&lt;/strong&gt; को संदर्भित करता था।&lt;/li&gt;
	&lt;li&gt;भूक्तियों का शासन &lt;strong&gt;&amp;#39;उपरिक&amp;#39;&lt;/strong&gt; नामक अधिकारियों द्वारा किया जाता था, जिन्हें राजा द्वारा नियुक्त किया जाता था।&lt;/li&gt;
	&lt;li&gt;प्रत्येक भूक्ति में कई &lt;strong&gt;&amp;#39;विषय&amp;#39;&lt;/strong&gt; या जिले शामिल थे, जो छोटी प्रशासनिक इकाइयाँ थीं।&lt;/li&gt;
	&lt;li&gt;विषयों का प्रबंधन &lt;strong&gt;&amp;#39;विषयपति&amp;#39;&lt;/strong&gt; नामक अधिकारियों द्वारा किया जाता था, जो भूक्ति के उपरिकों को रिपोर्ट करते थे।&lt;/li&gt;
	&lt;li&gt;गुप्तोत्तर काल में भुक्तियाँ विकेन्द्रित प्रशासनिक संरचना की एक प्रमुख विशेषता थी।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;उपरिक:&lt;/strong&gt; भूक्ति का प्रमुख, राजा द्वारा नियुक्त, जिसके पास प्रांत पर प्रशासनिक और न्यायिक अधिकार था।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विषय:&lt;/strong&gt; भूक्ति का एक उप-विभाग, जिले के समतुल्य, विषयपतियों द्वारा प्रबंधित।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;गुप्तोत्तर राजनीति:&lt;/strong&gt; इस काल में अधिक विकेंद्रीकृत प्रशासनिक व्यवस्था की ओर बदलाव देखा गया, जिसमें प्रांतों ने शासन में महत्वपूर्ण भूमिका निभाई।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विकेंद्रीकरण:&lt;/strong&gt; गुप्तोत्तर प्रशासन की विशेषता केन्द्रीय और प्रान्तीय प्राधिकारियों के बीच सत्ता का विभाजन थी।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;गुप्त प्रशासन:&lt;/strong&gt; &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;गुप्त काल ने भूक्ति और विषय जैसी प्रशासनिक इकाइयों की नींव रखी, जो गुप्तोत्तर राजनीति में जारी रहीं।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Dubai.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The UAE unveiled its first Sovereign Mobility Cloud at the Dubai World Congress for Self-Driving Transport, marking a key step in the country&amp;rsquo;s autonomous mobility strategy.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The Sovereign Mobility Cloud provides a secure, sovereign-enabled platform for hosting mobility data and autonomous system operations within UAE jurisdiction.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;All data and infrastructure are governed under UAE national regulations, ensuring data security and compliance.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Autonomous mobility technologies integrated include LiDAR, AI, and GPS, enabling vehicles to navigate safely without human input.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The initiative reflects the UAE&amp;rsquo;s commitment to advancing smart transport and autonomous vehicle strategies at a national level.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Sovereign Mobility Cloud&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;A platform providing trusted infrastructure for autonomous vehicles and mobility data, fully hosted within UAE to ensure national regulatory compliance.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Autonomous Mobility&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Involves vehicles operating with minimal or no human input using AI, LiDAR, and GPS to perceive surroundings, make decisions, and navigate safely.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;LiDAR Technology&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Light Detection and Ranging (LiDAR) is used to detect objects and map environments in 3D for autonomous navigation.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Strategic Significance&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;The initiative strengthens the UAE&amp;rsquo;s leadership in autonomous transport, providing secure, locally governed digital infrastructure for future mobility innovations.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;दुबई&lt;/strong&gt;&lt;/u&gt; है।&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;UAE ने सेल्फ-ड्राइविंग ट्रांसपोर्ट के लिए दुबई वर्ल्ड कांग्रेस में अपना पहला सॉवरेन मोबिलिटी क्लाउड लॉन्च किया, जो देश की स्वायत्त गतिशीलता रणनीति में एक महत्वपूर्ण कदम है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;सॉवरेन मोबिलिटी क्लाउड UAE के क्षेत्राधिकार में मोबिलिटी डेटा और स्वायत्त प्रणाली संचालन की मेजबानी के लिए एक सुरक्षित, संप्रभु-सक्षम मंच प्रदान करता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सभी डेटा और बुनियादी ढांचे UAE के राष्ट्रीय नियमों के तहत शासित होते हैं, जो डेटा सुरक्षा और अनुपालन सुनिश्चित करते हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;एकीकृत स्वायत्त गतिशीलता प्रौद्योगिकियों में LiDAR, AI और GPS शामिल हैं, जो वाहनों को बिना मानवीय इनपुट के सुरक्षित रूप से नेविगेट करने में सक्षम बनाते हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;यह पहल राष्ट्रीय स्तर पर स्मार्ट परिवहन और स्वायत्त वाहन रणनीतियों को आगे बढ़ाने के लिए UAE की प्रतिबद्धता को दर्शाती है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;सॉवरेन मोबिलिटी क्लाउड&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;एक ऐसा प्लेटफॉर्म जो स्वायत्त वाहनों और मोबिलिटी डेटा के लिए विश्वसनीय बुनियादी ढांचा प्रदान करता है, जो राष्ट्रीय नियामक अनुपालन सुनिश्चित करने के लिए UAE के भीतर पूरी तरह से होस्ट किया जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;स्वायत्त गतिशीलता&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;इसमें AI, LiDAR और GPS का उपयोग करके न्यूनतम या बिना मानवीय इनपुट के संचालित होने वाले वाहन शामिल होते हैं, जो आसपास की चीजों को समझने, निर्णय लेने और सुरक्षित रूप से नेविगेट करने के लिए होते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;LiDAR प्रौद्योगिकी&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;LiDAR (लाइट डिटेक्शन एंड रेंजिंग) का उपयोग स्वायत्त नेविगेशन के लिए वस्तुओं का पता लगाने और 3D में वातावरण का मानचित्रण करने के लिए किया जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;रणनीतिक महत्व&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;यह पहल स्वायत्त परिवहन में UAE के नेतृत्व को मजबूत करती है, भविष्य की गतिशीलता नवाचारों के लिए सुरक्षित, स्थानीय रूप से शासित डिजिटल बुनियादी ढांचा प्रदान करती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;&quot;&gt;&lt;u&gt;&lt;strong&gt;Bering Strait.&lt;/strong&gt;&lt;/u&gt;&lt;br /&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;br /&gt;
A &lt;strong&gt;Strait &lt;/strong&gt;is a naturally formed, narrow, typically navigable waterway that connects two larger bodies of water.&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width: 350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&lt;strong&gt;&amp;nbsp;Straits&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&lt;strong&gt;&amp;nbsp;Connections&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;Gibraltar Strait&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;It conn\ects the &lt;strong&gt;Atlantic &lt;/strong&gt;&lt;strong&gt;Ocean &lt;/strong&gt;to&lt;strong&gt; the Mediterranean sea.&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;Dover Strait&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;It connects the boundary between the &lt;strong&gt;English Channel &lt;/strong&gt;and&lt;strong&gt; the North Sea&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;Bering Strait&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;It connects the &lt;strong&gt;Arctic &lt;/strong&gt;&lt;strong&gt;Ocean &lt;/strong&gt;with the &lt;strong&gt;Pacific Ocean&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;Sunda Strait&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;It connects the&amp;nbsp;&lt;strong&gt;Java sea &lt;/strong&gt;to&lt;strong&gt; the Indian Ocean&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p&gt;सही उत्&amp;zwj;तर &lt;u&gt;&lt;strong&gt;बेरिंग जलडमरूमध्य&amp;nbsp;&lt;/strong&gt;&lt;/u&gt;है।&amp;nbsp;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;जलडमरूमध्य&lt;/strong&gt; प्राकृतिक रूप से निर्मित, एक संकीर्ण, आमतौर पर नौगम्य जलमार्ग है जो पानी के दो बड़े निकायों को जोड़ता है।&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width: 350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;जलडमरूमध्य&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;संपर्क&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;जिब्राल्टर जलडमरूमध्य&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;यह अटलांटिक महासागर को भूमध्य सागर से जोड़ता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;डोवर जलडमरूमध्य&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;यह अंग्रेजी चैनल और उत्तरी सागर के बीच की सीमा को जोड़ता है&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;बेरिंग जलडमरूमध्य&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;यह आर्कटिक महासागर को प्रशांत महासागर से जोड़ता है&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;सुंडा जलडमरूमध्य&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;यह जावा सागर को हिंद महासागर से जोड़ता है&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;23 March.&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

